    if (parityRatio < 0.8) {
      context.setError(`Bias detected: Disparity ratio ${parityRatio.toFixed(3)}`);
      throw new Error('FAIRNESS_VIOLATION');
    }

    context.output = { ...output, biasMetrics: { parityRatio } };
  }
};

